1	//! `LuaValue` — the tagged-union value type. PORT_STRATEGY §3.2.
2	
3	use crate::closure::LuaClosure;
4	use crate::gc::GcRef;
5	use crate::string::LuaString;
6	use crate::userdata::LuaUserData;
7	use std::ffi::c_void;
8	
9	/// The dynamically-typed Lua value. Replaces C's `TValue`.
10	#[derive(Debug, Clone)]
11	pub enum LuaValue {
12	    Nil,
13	    Bool(bool),
14	    Int(i64),
15	    Float(f64),
16	    Str(GcRef<LuaString>),
17	    Table(GcRef<LuaTable>),
18	    Function(LuaClosure),
19	    UserData(GcRef<LuaUserData>),
20	    LightUserData(*mut c_void),
21	    Thread(GcRef<LuaThread>),
22	}
23	
24	impl LuaValue {
25	    pub fn type_tag(&self) -> crate::LuaType {
26	        use crate::LuaType::*;
27	        match self {
28	            LuaValue::Nil               => Nil,
29	            LuaValue::Bool(_)           => Boolean,
30	            LuaValue::Int(_)            => Number,
31	            LuaValue::Float(_)          => Number,
32	            LuaValue::Str(_)            => String,
33	            LuaValue::Table(_)          => Table,
34	            LuaValue::Function(_)       => Function,
35	            LuaValue::UserData(_)       => UserData,
36	            LuaValue::LightUserData(_)  => LightUserData,
37	            LuaValue::Thread(_)         => Thread,
38	        }
39	    }
40	
41	    pub fn type_name(&self) -> &'static str {
42	        match self {
43	            LuaValue::Nil               => "nil",
44	            LuaValue::Bool(_)           => "boolean",
45	            LuaValue::Int(_)            => "number",
46	            LuaValue::Float(_)          => "number",
47	            LuaValue::Str(_)            => "string",
48	            LuaValue::Table(_)          => "table",
49	            LuaValue::Function(_)       => "function",
50	            LuaValue::UserData(_)       => "userdata",
51	            LuaValue::LightUserData(_)  => "userdata",
52	            LuaValue::Thread(_)         => "thread",
53	        }
54	    }
55	
56	    pub fn is_nil(&self) -> bool   { matches!(self, LuaValue::Nil) }
57	    pub fn is_falsy(&self) -> bool { matches!(self, LuaValue::Nil | LuaValue::Bool(false)) }
58	    pub fn is_truthy(&self) -> bool { !self.is_falsy() }
59	    pub fn is_collectable(&self) -> bool {
60	        matches!(self,
61	            LuaValue::Str(_) | LuaValue::Table(_) | LuaValue::Function(_) |
62	            LuaValue::UserData(_) | LuaValue::Thread(_))
63	    }
64	
65	    pub fn as_int(&self) -> Option<i64> {
66	        match self { LuaValue::Int(i) => Some(*i), _ => None }
67	    }
68	    pub fn as_float(&self) -> Option<f64> {
69	        match self { LuaValue::Float(f) => Some(*f), _ => None }
70	    }
71	    pub fn as_string(&self) -> Option<&GcRef<LuaString>> {
72	        match self { LuaValue::Str(s) => Some(s), _ => None }
73	    }
74	    pub fn as_table(&self) -> Option<&GcRef<LuaTable>> {
75	        match self { LuaValue::Table(t) => Some(t), _ => None }
76	    }
77	}
78	
79	impl Default for LuaValue {
80	    fn default() -> Self { LuaValue::Nil }
81	}
82	
83	impl PartialEq for LuaValue {
84	    fn eq(&self, other: &Self) -> bool {
85	        match (self, other) {
86	            (LuaValue::Nil, LuaValue::Nil) => true,
87	            (LuaValue::Bool(a), LuaValue::Bool(b)) => a == b,
88	            (LuaValue::Int(a), LuaValue::Int(b)) => a == b,
89	            (LuaValue::Float(a), LuaValue::Float(b)) => a == b,
90	            (LuaValue::Str(a), LuaValue::Str(b)) => GcRef::ptr_eq(a, b) || a.as_bytes() == b.as_bytes(),
91	            (LuaValue::Table(a), LuaValue::Table(b)) => GcRef::ptr_eq(a, b),
92	            (LuaValue::Function(a), LuaValue::Function(b)) => closure_eq(a, b),
93	            (LuaValue::UserData(a), LuaValue::UserData(b)) => GcRef::ptr_eq(a, b),
94	            (LuaValue::LightUserData(a), LuaValue::LightUserData(b)) => a == b,
95	            (LuaValue::Thread(a), LuaValue::Thread(b)) => GcRef::ptr_eq(a, b),
96	            _ => false,
97	        }
98	    }
99	}
100	
101	/// Float-to-integer rounding mode (matches C-Lua's F2Imod).
102	#[derive(Debug, Clone, Copy, PartialEq, Eq)]
103	pub enum F2Imod {
104	    Floor,
105	    Ceil,
106	    Round,
107	}
108	
109	// Heap-allocated value types. LuaTable now holds real (Vec-backed) storage —
110	// previously this was a placeholder unit struct and writes/reads were no-ops,
111	// causing `print` registration to silently fail in `open_libs`. The rich
112	// array+hash version in `lua-vm/src/table.rs` is a Phase-D performance
113	// upgrade target; the simple Vec-pair implementation here is correct for
114	// Lua semantics and unblocks the runtime.
115	
116	use std::cell::{Cell, RefCell};
117	
118	const WEAK_KEYS: u8 = 1 << 0;
119	const WEAK_VALUES: u8 = 1 << 1;
120	
121	#[derive(Debug, Default)]
122	pub struct LuaTable {
123	    entries: RefCell<Vec<(LuaValue, LuaValue)>>,
124	    metatable: RefCell<Option<GcRef<LuaTable>>>,
125	    weak_mode: Cell<u8>,
126	}
127	
128	impl LuaTable {
129	    pub fn placeholder() -> Self { Self::default() }
130	
131	    /// Read a key; returns `LuaValue::Nil` if absent or if key is nil.
132	    ///
133	    /// If this table has weak keys or values (`__mode`), any matching entry
134	    /// whose weakly-tagged component has no other strong holders (Rc
135	    /// `strong_count == 1`) is removed and `Nil` is returned. This is the
136	    /// Phase-A/B/C stand-in for the real incremental sweeper.
137	    pub fn get(&self, k: &LuaValue) -> LuaValue {
138	        if matches!(k, LuaValue::Nil) { return LuaValue::Nil; }
139	        let mode = self.weak_mode.get();
140	        if mode != 0 {
141	            let entries = self.entries.borrow();
142	            let found = entries.iter().position(|(ek, _)| lua_key_eq(ek, k));
143	            if let Some(i) = found {
144	                let (ek, ev) = &entries[i];
145	                let dead = entry_is_weakly_dead(ek, ev, mode);
146	                if dead {
147	                    drop(entries);
148	                    self.entries.borrow_mut().swap_remove(i);
149	                    return LuaValue::Nil;
150	                }
151	                return ev.clone();
152	            }
153	            return LuaValue::Nil;
154	        }
155	        for (ek, ev) in self.entries.borrow().iter() {
156	            if lua_key_eq(ek, k) { return ev.clone(); }
157	        }
158	        LuaValue::Nil
159	    }
160	
161	    /// Lookup by short-string key (used by metatable __index lookups).
162	    pub fn get_short_str(&self, k: &GcRef<crate::string::LuaString>) -> LuaValue {
163	        let key = LuaValue::Str(k.clone());
164	        self.get(&key)
165	    }
166	
167	    /// Raw set without metamethod dispatch. nil keys are rejected (Lua
168	    /// semantics: `table[nil] = x` is an error; we silently ignore here
169	    /// since callers should validate). Setting a value to nil clears the
170	    /// slot's value but retains the key as a tombstone so that
171	    /// `next(t, k)` callers iterating while erasing can still locate the
172	    /// last-yielded key — matching C-Lua's hash-slot semantics.
173	    pub fn raw_set(&self, k: LuaValue, v: LuaValue) {
174	        if matches!(k, LuaValue::Nil) { return; }
175	        let mut entries = self.entries.borrow_mut();
176	        for i in 0..entries.len() {
177	            if lua_key_eq(&entries[i].0, &k) {
178	                entries[i].1 = v;
179	                return;
180	            }
181	        }
182	        if !matches!(v, LuaValue::Nil) {
183	            entries.push((k, v));
184	        }
185	    }
186	
187	    /// Returns true if `k` is currently a slot in the entries table,
188	    /// regardless of whether its value is nil. Used by `next` to
189	    /// distinguish "key was here (now value=nil)" from "key was never
190	    /// inserted" — only the latter is an "invalid key to 'next'" error.
191	    pub fn contains_key(&self, k: &LuaValue) -> bool {
192	        if matches!(k, LuaValue::Nil) { return false; }
193	        self.entries.borrow().iter().any(|(ek, _)| lua_key_eq(ek, k))
194	    }
195	
196	    pub fn metatable(&self) -> Option<GcRef<LuaTable>> {
197	        self.metatable.borrow().clone()
198	    }
199	
200	    pub fn set_metatable(&self, mt: Option<GcRef<LuaTable>>) {
201	        let mode = mt.as_ref().map(|t| extract_weak_mode(t)).unwrap_or(0);
202	        self.weak_mode.set(mode);
203	        *self.metatable.borrow_mut() = mt;
204	    }
205	
206	    pub fn len(&self) -> usize { self.entries.borrow().len() }
207	    pub fn is_empty(&self) -> bool { self.entries.borrow().is_empty() }
208	
209	    /// Implements Lua's `next(t, k)` for iteration. When `k` is `Nil`,
210	    /// returns the first entry. Otherwise returns the entry that follows
211	    /// `k` in insertion order. Returns `None` when iteration is done.
212	    ///
213	    /// Skips weakly-dead entries on the way; this keeps `pairs()` over a
214	    /// weak table from observing collected slots.
215	    pub fn next_pair(&self, k: &LuaValue) -> Option<(LuaValue, LuaValue)> {
216	        let mode = self.weak_mode.get();
217	        if mode != 0 {
218	            let mut entries = self.entries.borrow_mut();
219	            entries.retain(|(ek, ev)| !entry_is_weakly_dead(ek, ev, mode));
220	        }
221	        let entries = self.entries.borrow();
222	        let start = if matches!(k, LuaValue::Nil) {
223	            0
224	        } else {
225	            let mut found = None;
226	            for (i, (ek, _)) in entries.iter().enumerate() {
227	                if lua_key_eq(ek, k) { found = Some(i + 1); break; }
228	            }
229	            found?
230	        };
231	        for (ek, ev) in entries[start..].iter() {
232	            if !matches!(ev, LuaValue::Nil) {
233	                return Some((ek.clone(), ev.clone()));
234	            }
235	        }
236	        None
237	    }
238	}
239	
240	/// Inspect a metatable's `__mode` field (a string of any combination of
241	/// 'k' and 'v') and produce the corresponding `WEAK_KEYS | WEAK_VALUES`
242	/// bitmask. Returns 0 when no `__mode` is set or it is not a string.
243	fn extract_weak_mode(mt: &LuaTable) -> u8 {
244	    let entries = mt.entries.borrow();
245	    for (k, v) in entries.iter() {
246	        if let LuaValue::Str(ks) = k {
247	            if ks.as_bytes() == b"__mode" {
248	                if let LuaValue::Str(vs) = v {
249	                    let bytes = vs.as_bytes();
250	                    let mut mode = 0u8;
251	                    if bytes.iter().any(|b| *b == b'k') { mode |= WEAK_KEYS; }
252	                    if bytes.iter().any(|b| *b == b'v') { mode |= WEAK_VALUES; }
253	                    return mode;
254	                }
255	                return 0;
256	            }
257	        }
258	    }
259	    0
260	}
261	
262	/// True when the entry's weakly-tagged component(s) are held only by this
263	/// table (Rc `strong_count == 1`). Strings are skipped — they tend to be
264	/// interned in long-lived caches and would otherwise vanish from weak
265	/// caches almost immediately.
266	fn entry_is_weakly_dead(k: &LuaValue, v: &LuaValue, mode: u8) -> bool {
267	    if (mode & WEAK_KEYS) != 0 && weakly_held_alone(k) {
268	        return true;
269	    }
270	    if (mode & WEAK_VALUES) != 0 && weakly_held_alone(v) {
271	        return true;
272	    }
273	    false
274	}
275	
276	fn weakly_held_alone(v: &LuaValue) -> bool {
277	    use std::rc::Rc;
278	    match v {
279	        LuaValue::Table(t)    => Rc::strong_count(&t.0) == 1,
280	        LuaValue::UserData(u) => Rc::strong_count(&u.0) == 1,
281	        LuaValue::Thread(th)  => Rc::strong_count(&th.0) == 1,
282	        LuaValue::Function(c) => match c {
283	            LuaClosure::Lua(x)    => Rc::strong_count(&x.0) == 1,
284	            LuaClosure::C(x)      => Rc::strong_count(&x.0) == 1,
285	            LuaClosure::LightC(_) => false,
286	        },
287	        _ => false,
288	    }
289	}
290	
291	fn closure_eq(a: &LuaClosure, b: &LuaClosure) -> bool {
292	    match (a, b) {
293	        (LuaClosure::Lua(x), LuaClosure::Lua(y)) => GcRef::ptr_eq(x, y),
294	        (LuaClosure::C(x), LuaClosure::C(y)) => GcRef::ptr_eq(x, y),
295	        (LuaClosure::LightC(x), LuaClosure::LightC(y)) => x == y,
296	        _ => false,
297	    }
298	}
299	
300	/// Key equality for hash-table lookup. Matches Lua semantics:
301	///   - Nil never equals anything (handled at call sites)
302	///   - Bool/Int/Float/String compare by value
303	///   - Int <-> Float compare numerically (Lua coerces)
304	///   - Table/Function/UserData/Thread compare by GcRef identity
305	fn lua_key_eq(a: &LuaValue, b: &LuaValue) -> bool {
306	    match (a, b) {
307	        (LuaValue::Nil, LuaValue::Nil) => true,
308	        (LuaValue::Bool(x), LuaValue::Bool(y)) => x == y,
309	        (LuaValue::Int(x), LuaValue::Int(y)) => x == y,
310	        (LuaValue::Float(x), LuaValue::Float(y)) => x == y,
311	        (LuaValue::Int(i), LuaValue::Float(f)) | (LuaValue::Float(f), LuaValue::Int(i)) => *f == *i as f64,
312	        (LuaValue::Str(x), LuaValue::Str(y)) => x.as_bytes() == y.as_bytes(),
313	        (LuaValue::Table(x), LuaValue::Table(y)) => GcRef::ptr_eq(x, y),
314	        (LuaValue::UserData(x), LuaValue::UserData(y)) => GcRef::ptr_eq(x, y),
315	        (LuaValue::Thread(x), LuaValue::Thread(y)) => GcRef::ptr_eq(x, y),
316	        (LuaValue::Function(x), LuaValue::Function(y)) => closure_eq(x, y),
317	        (LuaValue::LightUserData(x), LuaValue::LightUserData(y)) => x == y,
318	        _ => false,
319	    }
320	}
321	
322	#[derive(Debug)]
323	pub struct LuaThread {
324	    _private: (),
325	}
326	impl LuaThread {
327	    pub fn placeholder() -> Self { LuaThread { _private: () } }
328	}
