44	/// A traced color in the tri-color invariant.
45	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
46	pub enum Color {
47	    /// Not yet visited this cycle. Candidate for sweep.
48	    White,
49	    /// Visited; outgoing references not yet traced.
50	    Gray,
51	    /// Fully traced; no outgoing pointers to white objects.
52	    Black,
53	}
54	
55	/// Per-object GC metadata. Lives at the start of every `GcBox`.
56	#[repr(C)]
57	pub struct GcHeader {
58	    color: Cell<Color>,
59	    /// Set true after this object's finalizer (`__gc` metamethod) has run.
60	    /// Phase D defers finalizers; this is reserved.
61	    finalized: Cell<bool>,
62	    /// Intrusive link into the heap's allgc chain.
63	    next: Cell<Option<NonNull<GcBox<dyn Trace>>>>,
64	    /// Rough byte size of the contained value; used for memory accounting.
65	    size: usize,
66	}
67	
68	impl GcHeader {
69	    fn new_white(size: usize) -> Self {
70	        Self {
71	            color: Cell::new(Color::White),
72	            finalized: Cell::new(false),
73	            next: Cell::new(None),
74	            size,
75	        }
76	    }
77	}
