95	/// A GC-managed pointer. Copy + Clone (one-machine-word). Replaces `GcRef<T>`.
96	pub struct Gc<T: ?Sized> {
97	    ptr: NonNull<GcBox<T>>,
98	    /// Marker so `Gc<T>` is treated as if it owns `T` for variance.
99	    _marker: PhantomData<T>,
100	}
