102	// SAFETY: Gc is just a pointer. The Cell-based interior mutability of the
103	// header is single-threaded (the entire Lua runtime is single-threaded), so
104	// no Send/Sync impls are needed and we don't provide them.
105	impl<T: ?Sized> Copy for Gc<T> {}
106	impl<T: ?Sized> Clone for Gc<T> {
107	    fn clone(&self) -> Self {
108	        *self
109	    }
