131	impl<T: Trace + 'static> Gc<T> {
132	    /// Allocate a `GcBox<T>` outside any heap registry. Used by legacy
133	    /// `GcRef::new` call sites until Phase D-1b migrates them. The returned
134	    /// `Gc<T>` is reachable only through the caller's own retention path;
135	    /// without joining a heap's allgc chain, it will never be swept (so
136	    /// effectively leaks until process exit — same as Rc behavior).
137	    pub fn new_uncollected(value: T) -> Self {
138	        let size = std::mem::size_of::<T>();
139	        let boxed = Box::new(GcBox {
140	            header: GcHeader::new_white(size),
141	            value,
142	        });
143	        Gc {
144	            ptr: NonNull::new(Box::into_raw(boxed)).expect("Box::into_raw is non-null"),
145	            _marker: PhantomData,
146	        }
147	    }
148	}
149	
150	impl<T: ?Sized> Gc<T> {
151	    /// Two `Gc<T>`s are identity-equal iff they point at the same box.
152	    pub fn ptr_eq(a: Self, b: Self) -> bool {
153	        std::ptr::addr_eq(a.ptr.as_ptr(), b.ptr.as_ptr())
154	    }
155	
156	    /// Identity as a usize — usable as a hash table key for "is the *same
157	    /// object*" lookups.
158	    pub fn identity(self) -> usize {
159	        self.ptr.as_ptr() as *const () as usize
160	    }
161	
162	    /// Access the underlying value. Returns `&T` so callers can read fields
163	    /// without taking the `Gc` apart. Interior mutability lives inside T's
164	    /// own fields (Cell, RefCell, etc.).
165	    fn as_box(&self) -> &GcBox<T> {
166	        // SAFETY: A Gc<T> is constructed only by allocate() or
167	        // new_uncollected(), both of which produce a valid GcBox. The box
168	        // outlives the Gc until sweep, which only frees boxes not reachable
169	        // from any root — so as long as this Gc is on the stack or in a
170	        // traced field, the box is live.
171	        unsafe { self.ptr.as_ref() }
172	    }
173	
174	    fn header(&self) -> &GcHeader {
175	        &self.as_box().header
176	    }
177	}
178	
179	impl<T: ?Sized> std::ops::Deref for Gc<T> {
180	    type Target = T;
181	    fn deref(&self) -> &T {
182	        &self.as_box().value
183	    }
184	}
185	
186	impl<T: ?Sized> AsRef<T> for Gc<T> {
187	    fn as_ref(&self) -> &T {
188	        &self.as_box().value
189	    }
190	}
