192	/// Every GC-rooted type implements `Trace` to expose its `Gc<_>` fields.
193	///
194	/// The `trace` method visits every reachable `Gc<_>` and calls
195	/// `Marker::mark` on it. For container fields (`Vec<LuaValue>`, etc.) call
196	/// `field.trace(m)` to delegate.
197	///
198	/// # Mechanical pattern
199	///
200	/// ```ignore
201	/// impl Trace for LuaTable {
202	///     fn trace(&self, m: &mut Marker) {
203	///         for v in self.array.iter() { v.trace(m); }
204	///         if let Some(mt) = self.metatable { m.mark(mt); }
205	///     }
206	/// }
207	/// ```
208	pub trait Trace {
209	    fn trace(&self, m: &mut Marker);
210	}
211	
212	// Common blanket impls so most container types Just Work.
213	impl<T: Trace> Trace for Vec<T> {
214	    fn trace(&self, m: &mut Marker) {
215	        for item in self.iter() {
216	            item.trace(m);
217	        }
218	    }
219	}
