247	/// `Gc<T>` is itself traceable: marking it forwards to the contained `T`.
248	impl<T: Trace + 'static> Trace for Gc<T> {
249	    fn trace(&self, m: &mut Marker) {
250	        m.mark(*self);
251	    }
252	}
