254	// Trivially-traceable primitive types: visiting does nothing.
255	macro_rules! trace_noop {
256	    ($($t:ty),*) => {
257	        $(impl Trace for $t {
258	            fn trace(&self, _m: &mut Marker) {}
259	        })*
260	    };
261	}
262	trace_noop!(
263	    bool, u8, u16, u32, u64, u128, usize,
264	    i8, i16, i32, i64, i128, isize,
265	    f32, f64, char, String, str
266	);
