272	/// Holds the gray queue during a mark phase. Passed to `Trace::trace`.
273	pub struct Marker {
274	    gray_queue: Vec<NonNull<GcBox<dyn Trace>>>,
275	}
276	
277	impl Marker {
278	    fn new() -> Self {
279	        Self {
280	            gray_queue: Vec::with_capacity(256),
281	        }
282	    }
283	
284	    /// Mark a `Gc<T>` as gray (reachable, but its outgoing edges not yet
285	    /// traced). Called by `Trace::trace` implementations.
286	    pub fn mark<T: Trace + 'static>(&mut self, gc: Gc<T>) {
287	        let header = gc.header();
288	        if header.color.get() == Color::White {
289	            header.color.set(Color::Gray);
290	            // Coerce to NonNull<GcBox<dyn Trace>> so we can store in a
291	            // heterogeneous queue. Requires T: Sized for the unsizing.
292	            let ptr: NonNull<GcBox<dyn Trace>> = gc.ptr;
293	            self.gray_queue.push(ptr);
294	        }
295	    }
296	}
