298	/// Phases of the collection cycle. Currently only Idle and StopTheWorld are
299	/// used; placeholders for future incremental mode.
300	#[derive(Copy, Clone, PartialEq, Eq, Debug)]
301	pub enum GcState {
302	    Idle,
303	    Collecting,
304	}
305	
306	/// The heap. One per `GlobalState`. Owns the intrusive allgc list of every
307	/// allocated `GcBox`, tracks total bytes, and runs collections.
308	pub struct Heap {
309	    /// Head of the singly-linked allgc list (every live `GcBox`).
310	    head: Cell<Option<NonNull<GcBox<dyn Trace>>>>,
311	    /// Total bytes allocated (sum of header sizes; rough).
312	    bytes: Cell<usize>,
313	    /// Threshold above which `step` triggers a collection.
314	    threshold: Cell<usize>,
315	    /// Multiplier on bytes_used to set next threshold after collection.
316	    pause_multiplier: Cell<usize>,
317	    /// State machine. Mostly Idle; transitions during full_collect.
318	    state: Cell<GcState>,
319	    /// If true, `step` and `barrier` are no-ops (for bootstrap before the
320	    /// world is consistent).
321	    paused: Cell<bool>,
322	    /// Counter of full collections performed (for diagnostics).
323	    collections: Cell<usize>,
324	}
325	
326	impl Default for Heap {
327	    fn default() -> Self {
328	        Self::new()
329	    }
330	}
331	
332	impl Heap {
333	    pub fn new() -> Self {
334	        Self {
335	            head: Cell::new(None),
336	            bytes: Cell::new(0),
337	            threshold: Cell::new(64 * 1024), // initial threshold: 64 KB
338	            pause_multiplier: Cell::new(200), // 200% = collect when bytes 2x threshold
339	            state: Cell::new(GcState::Idle),
340	            paused: Cell::new(true), // start paused; caller enables when world is consistent
341	            collections: Cell::new(0),
342	        }
343	    }
344	
345	    /// Enable collection. Until this is called, `step` is a no-op (so the
346	    /// runtime can bootstrap without prematurely freeing objects).
347	    pub fn unpause(&self) {
348	        self.paused.set(false);
349	    }
350	
351	    pub fn is_paused(&self) -> bool {
352	        self.paused.get()
353	    }
354	
355	    /// Allocate a new `GcBox<T>` and prepend it to the allgc chain.
356	    pub fn allocate<T: Trace + 'static>(&self, value: T) -> Gc<T> {
357	        let size = std::mem::size_of::<GcBox<T>>();
358	        let boxed = Box::new(GcBox {
359	            header: GcHeader::new_white(size),
360	            value,
361	        });
362	        let raw: *mut GcBox<T> = Box::into_raw(boxed);
363	        let ptr: NonNull<GcBox<T>> =
364	            NonNull::new(raw).expect("Box::into_raw is non-null");
365	        // Coerce to dyn Trace for the intrusive list.
366	        let dyn_ptr: NonNull<GcBox<dyn Trace>> = ptr;
367	        // SAFETY: ptr is a freshly allocated GcBox; we hold the only handle
368	        // until we publish it into self.head and return Gc<T> to the caller.
369	        unsafe {
370	            (*raw).header.next.set(self.head.get());
371	        }
372	        self.head.set(Some(dyn_ptr));
373	        self.bytes.set(self.bytes.get() + size);
374	        Gc {
375	            ptr,
376	            _marker: PhantomData,
377	        }
378	    }
379	
380	    /// Bytes currently retained by GC-tracked objects (rough estimate).
381	    pub fn bytes_used(&self) -> usize {
382	        self.bytes.get()
383	    }
384	
385	    pub fn collections(&self) -> usize {
386	        self.collections.get()
387	    }
388	
389	    /// Forward write barrier: invoked when `parent` (already-traced black
390	    /// object) gains a new reference to `child`. To preserve the tri-color
391	    /// invariant ("no black points to white"), we mark the child gray
392	    /// immediately. Cheap: one branch + maybe one queue push.
393	    ///
394	    /// During incremental mode this prevents the marking phase from missing
395	    /// the new edge. In current stop-the-world mode it's still correct (a
396	    /// no-op when the collection is idle), so call sites can be wired now
397	    /// and the incremental upgrade is mechanical later.
398	    pub fn barrier<P, C>(&self, parent: Gc<P>, child: Gc<C>)
399	    where
400	        P: Trace + 'static,
401	        C: Trace + 'static,
402	    {
403	        if self.paused.get() || self.state.get() == GcState::Idle {
404	            return;
405	        }
406	        if parent.header().color.get() != Color::Black {
407	            return;
408	        }
409	        if child.header().color.get() != Color::White {
410	            return;
411	        }
412	        child.header().color.set(Color::Gray);
413	        // Push child onto the active marker's gray queue. The marker lives
414	        // on the stack during `full_collect`; we have no handle here. For
415	        // stop-the-world this branch is unreachable (state != Collecting
416	        // outside `full_collect`), so we don't yet store a gray queue on
417	        // self. Phase D-2 (incremental) will move the queue onto the Heap.
418	        debug_assert!(
419	            self.state.get() == GcState::Idle,
420	            "barrier hit during Collecting in stop-the-world phase D-0"
421	        );
422	    }
423	
424	    /// Possibly run a collection. Trigger: bytes_used > threshold.
425	    /// Caller passes the root set (the runtime — typically `GlobalState`
426	    /// implementing `Trace`).
427	    pub fn step(&self, roots: &dyn Trace) {
428	        if self.paused.get() {
429	            return;
430	        }
431	        if self.bytes.get() < self.threshold.get() {
432	            return;
433	        }
434	        self.full_collect(roots);
435	    }
436	
437	    /// Stop-the-world full collect. Marks every reachable object from
438	    /// `roots`, then sweeps white (unreachable) boxes from the allgc chain.
439	    pub fn full_collect(&self, roots: &dyn Trace) {
440	        if self.paused.get() {
441	            return;
442	        }
443	        self.state.set(GcState::Collecting);
444	
445	        // ── Mark phase ──────────────────────────────────────────────────
446	        let mut marker = Marker::new();
447	        // Reset all colors to White first (we're stop-the-world; no
448	        // incremental state to preserve).
449	        let mut cursor = self.head.get();
450	        while let Some(ptr) = cursor {
451	            // SAFETY: every entry in the allgc chain is a valid GcBox.
452	            let header = unsafe { &(*ptr.as_ptr()).header };
453	            header.color.set(Color::White);
454	            cursor = header.next.get();
455	        }
456	
457	        // Trace from roots.
458	        roots.trace(&mut marker);
459	
460	        // Drain the gray queue.
461	        while let Some(gray_ptr) = marker.gray_queue.pop() {
462	            // SAFETY: gray_queue only ever contains pointers added via
463	            // Marker::mark, which read them from valid Gc<T> handles.
464	            unsafe {
465	                let bx = gray_ptr.as_ref();
466	                bx.header.color.set(Color::Black);
467	                bx.value.trace(&mut marker);
468	            }
469	        }
470	
471	        // ── Sweep phase ─────────────────────────────────────────────────
472	        // Walk allgc; drop white boxes, keep black. Reset black→white for
473	        // next cycle.
474	        let mut prev_next: &Cell<Option<NonNull<GcBox<dyn Trace>>>> = &self.head;
475	        let mut cursor = prev_next.get();
476	        let mut freed_bytes = 0usize;
477	        while let Some(ptr) = cursor {
478	            // SAFETY: cursor walks the allgc chain; every entry is a valid
479	            // GcBox.
480	            let header = unsafe { &(*ptr.as_ptr()).header };
481	            let next = header.next.get();
482	            match header.color.get() {
483	                Color::White => {
484	                    // Unreachable. Unlink, drop, dealloc.
485	                    prev_next.set(next);
486	                    freed_bytes += header.size;
487	                    // SAFETY: ptr is a uniquely-owned NonNull<GcBox<...>>
488	                    // that we are about to drop. After this, nothing else
489	                    // references it.
490	                    unsafe {
491	                        let _ = Box::from_raw(ptr.as_ptr());
492	                    }
493	                }
494	                Color::Black | Color::Gray => {
495	                    header.color.set(Color::White);
496	                    // Advance prev_next to this box's next-cell.
497	                    // SAFETY: same as above.
498	                    prev_next = unsafe { &(*ptr.as_ptr()).header.next };
499	                }
500	            }
501	            cursor = next;
502	        }
503	
504	        self.bytes.set(self.bytes.get().saturating_sub(freed_bytes));
505	        self.threshold
506	            .set(self.bytes.get() * self.pause_multiplier.get() / 100);
507	        self.collections.set(self.collections.get() + 1);
508	        self.state.set(GcState::Idle);
509	    }
510	
511	    /// Drop every allocation, ignoring reachability. Called at shutdown.
512	    /// After this returns, every outstanding `Gc<T>` is dangling — callers
513	    /// must ensure no `Gc<T>` outlives the `Heap`.
514	    pub fn drop_all(&self) {
515	        let mut cursor = self.head.get();
516	        self.head.set(None);
517	        while let Some(ptr) = cursor {
518	            // SAFETY: same chain invariant as full_collect's sweep.
519	            let next = unsafe { (*ptr.as_ptr()).header.next.get() };
520	            unsafe {
521	                let _ = Box::from_raw(ptr.as_ptr());
522	            }
523	            cursor = next;
524	        }
525	        self.bytes.set(0);
526	    }
527	}
528	
529	impl Drop for Heap {
530	    fn drop(&mut self) {
531	        self.drop_all();
532	    }
533	}
534	
535	// ──────────────────────────────────────────────────────────────────────────
536	// Tests — confirm the skeleton's invariants before agents ever touch it.
537	// ──────────────────────────────────────────────────────────────────────────
538	
539	#[cfg(test)]
540	mod tests {
541	    use super::*;
542	
543	    /// A tiny GC-tracked type for the smoke test.
544	    struct Cell0 {
545	        next: Cell<Option<Gc<Cell0>>>,
546	        marker_calls: Cell<usize>,
547	    }
548	
549	    impl Trace for Cell0 {
550	        fn trace(&self, m: &mut Marker) {
551	            self.marker_calls.set(self.marker_calls.get() + 1);
552	            if let Some(n) = self.next.get() {
553	                m.mark(n);
554	            }
555	        }
556	    }
557	
558	    /// Roots for tests: just a single Gc<Cell0>, or none.
559	    struct OneRoot(Option<Gc<Cell0>>);
560	    impl Trace for OneRoot {
561	        fn trace(&self, m: &mut Marker) {
562	            if let Some(g) = self.0 {
563	                m.mark(g);
564	            }
565	        }
566	    }
567	
568	    #[test]
569	    fn alloc_and_drop_all() {
570	        let heap = Heap::new();
571	        heap.unpause();
572	        let _a = heap.allocate(Cell0 {
573	            next: Cell::new(None),
574	            marker_calls: Cell::new(0),
575	        });
576	        let _b = heap.allocate(Cell0 {
577	            next: Cell::new(None),
578	            marker_calls: Cell::new(0),
579	        });
580	        assert!(heap.bytes_used() > 0);
581	        heap.drop_all();
582	        assert_eq!(heap.bytes_used(), 0);
583	    }
584	
585	    #[test]
586	    fn collect_unreachable_frees_bytes() {
587	        let heap = Heap::new();
588	        heap.unpause();
589	        let _a = heap.allocate(Cell0 {
590	            next: Cell::new(None),
591	            marker_calls: Cell::new(0),
592	        });
593	        let bytes_before = heap.bytes_used();
594	        assert!(bytes_before > 0);
595	        // No roots — everything should sweep.
596	        heap.full_collect(&OneRoot(None));
597	        assert_eq!(heap.bytes_used(), 0);
598	        assert_eq!(heap.collections(), 1);
599	    }
600	
601	    #[test]
602	    fn collect_keeps_reachable() {
603	        let heap = Heap::new();
604	        heap.unpause();
605	        let root = heap.allocate(Cell0 {
606	            next: Cell::new(None),
607	            marker_calls: Cell::new(0),
608	        });
609	        let bytes_before = heap.bytes_used();
610	        heap.full_collect(&OneRoot(Some(root)));
611	        assert_eq!(heap.bytes_used(), bytes_before);
612	        assert_eq!(root.marker_calls.get(), 1);
613	    }
614	
615	    #[test]
616	    fn collect_traverses_cycles() {
617	        let heap = Heap::new();
618	        heap.unpause();
619	        let a = heap.allocate(Cell0 {
620	            next: Cell::new(None),
621	            marker_calls: Cell::new(0),
622	        });
623	        let b = heap.allocate(Cell0 {
624	            next: Cell::new(Some(a)),
625	            marker_calls: Cell::new(0),
626	        });
627	        a.next.set(Some(b)); // cycle
628	        // With a as root, both should survive.
629	        heap.full_collect(&OneRoot(Some(a)));
630	        assert_eq!(a.marker_calls.get(), 1);
631	        assert_eq!(b.marker_calls.get(), 1);
632	        // Drop the only root path; cycle should now be collected.
633	        // (Note: `a` and `b` are still on the stack as Gc<Cell0> handles, but
634	        // they're not in a Trace-visible position.)
635	        heap.full_collect(&OneRoot(None));
636	        assert_eq!(heap.bytes_used(), 0);
637	    }
638	
639	    #[test]
640	    fn step_threshold_triggers_collect() {
641	        let heap = Heap::new();
642	        heap.unpause();
643	        // Allocate enough boxes to exceed the default 64KB threshold.
644	        let mut keeps = Vec::new();
645	        for _ in 0..64 {
646	            // ~1KB per box (Cell0 is small, but allocating many headers
647	            // accumulates). For the threshold test we'd typically allocate
648	            // larger objects; this is a smoke test.
649	            keeps.push(heap.allocate(Cell0 {
650	                next: Cell::new(None),
651	                marker_calls: Cell::new(0),
652	            }));
653	        }
654	        // Build roots that retain all of keeps via individual marks.
655	        struct ManyRoots<'a>(&'a [Gc<Cell0>]);
656	        impl<'a> Trace for ManyRoots<'a> {
657	            fn trace(&self, m: &mut Marker) {
658	                for g in self.0.iter() {
659	                    m.mark(*g);
660	                }
661	            }
662	        }
663	        heap.step(&ManyRoots(&keeps));
664	        // step is a no-op below threshold; all roots retained.
665	        assert!(heap.bytes_used() > 0);
666	    }
667	}
